            .putString(AuthConstants.PREF_ENCRYPTED_TOKEN, Base64.encodeToString(encryptedBytes, Base64.NO_WRAP))
            .putString(AuthConstants.PREF_TOKEN_IV, Base64.encodeToString(iv, Base64.NO_WRAP))
            .putBoolean(AuthConstants.PREF_BIOMETRIC_ENROLLED, true)
            .apply()

        Log.d(AuthConstants.TAG, "Encrypted session token stored successfully.")
    }

