            val decryptedBytes = cipher.doFinal(encryptedBytes)
            String(decryptedBytes, Charsets.UTF_8)
        } catch (e: Exception) {
            Log.e(AuthConstants.TAG, "Failed to decrypt session token", e)
            null
        }
    }

    /**
