                && prefs.getString(AuthConstants.PREF_ENCRYPTED_TOKEN, null) != null
                && prefs.getString(AuthConstants.PREF_TOKEN_IV, null) != null
    }

    /**
     * Get the stored IV for decryption.
     */
    fun getStoredIv(): ByteArray? {
        val ivBase64 = prefs.getString(AuthConstants.PREF_TOKEN_IV, null) ?: return null
        return Base64.decode(ivBase64, Base64.NO_WRAP)
    }

    /**
